import json

lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))
images = crash.get('usedImages', [])

# Thread names
print('=== THREAD NAMES ===')
for i, t in enumerate(crash.get('threads', [])):
    name = t.get('name', '')
    queue = t.get('queue', '')
    triggered = t.get('triggered', False)
    info = []
    if name: info.append(f'name=\"{name}\"')
    if queue: info.append(f'queue=\"{queue}\"')
    if triggered: info.append('TRIGGERED')
    print(f'  Thread {i}: {\" \".join(info) if info else \"(unnamed)\"}')

# Check if there's any diagnostic message or other crash info
print('\n=== OTHER KEYS ===')
for key in sorted(crash.keys()):
    if key not in ('threads', 'usedImages', 'legacyInfo'):
        val = crash[key]
        if isinstance(val, (str, int, float, bool)):
            print(f'  {key}: {val}')
        elif isinstance(val, dict) and len(str(val)) < 200:
            print(f'  {key}: {val}')
        elif isinstance(val, list) and len(val) < 5:
            print(f'  {key}: {val}')
        else:
            print(f'  {key}: ({type(val).__name__}, len={len(val) if hasattr(val,\"__len__\") else \"?\"})')
"

